const cluster = require('cluster');

const http    = require('http');

const os      = require('os');

if (cluster.isPrimary) {

  const numCPUs = os.cpus().length;

  for (let i = 0; i < numCPUs; i++) cluster.fork();

  cluster.on('exit', (worker) => {

    console.log('Worker ' + worker.pid + ' died. Restarting...');

    cluster.fork();

  });

} else {

  http.createServer((req, res) => {

    res.end('Worker ' + process.pid + ': Hello!');

  }).listen(3000);

}

*💡 Trong production, dùng PM2 thay vì tự viết cluster logic. PM2 có load balancing, monitoring, và zero-downtime restart sẵn có.*

The cluster module allows creating multiple child processes (workers) to take advantage of multi-core CPUs. All workers share the same server port.

*💡** In production, use PM2 instead of writing cluster logic manually. PM2 provides load balancing, monitoring, and zero-downtime restart out of the box.*

