const { Server } = require('socket.io');

const io = new Server(httpServer, { cors: { origin: 'https://myapp.com' } });

io.on('connection', (socket) => {

  socket.on('message', (data) => {

    io.emit('message', { from: socket.id, text: data });

  });

  socket.on('joinRoom', (room) => {

    socket.join(room);

    io.to(room).emit('notification', socket.id + ' joined!');

  });

  socket.on('disconnect', () => console.log('Client disconnected'));

});

WebSocket is a protocol that enables two-way (full-duplex) communication over a persistent connection — ideal for real-time apps (chat, live feeds, gaming).

