const { Worker, isMainThread, parentPort, workerData } = require('worker_threads');

if (isMainThread) {

  const worker = new Worker(__filename, { workerData: { numbers: [1,2,3,4,5] } });

  worker.on('message', result => console.log('Sum:', result));

} else {

  const sum = workerData.numbers.reduce((a, b) => a + b, 0);

  parentPort.postMessage(sum);

}

Worker Threads allow JavaScript to run in separate threads — solving the problem of CPU-intensive tasks blocking the event loop.

• Nature: A new thread within the same process (vs. Cluster/fork which spawns a separate process).

• Memory: Can share memory via SharedArrayBuffer (vs. fully isolated memory in Cluster).

• Startup cost: Low (milliseconds) — lower than spawning a new process.

• Isolation: Lower — a crash in a worker can affect the main thread.

• Use case: CPU-heavy tasks such as image resizing, cryptography, and ML inference.
